import { React, useEffect, useState } from 'react'
import { Container, Grid } from '@material-ui/core'
import SubjectCards from '../components/SubjectCards'
import axios from 'axios'
import kulas from '../images/kulas.png'
import daks from '../images/daks.png'
import phil from '../images/phil.png'
import mathbg from '../images/mathbg.png'
import webdev from '../images/webdevelopment.png'
import webdes from '../images/webdesign.png'
import js from '../images/javascript.png'
import arduino from '../images/arduino.png'
import engr from '../images/engineering.png'
import graphicdesign from '../images/graphicdesign.png'
import py from '../images/python.png'
import arts from '../images/arts.png'



export default function StudentDashboard() {

    // const [subjects, setSubjects] = useState([
    //     { title: 'Web Development', body: 'MWF (7:00AM-10:00AM)', instructor: 'Engr. Phil Cajurao', image: phil, imagebg: webdev, id: 1 },
    //     { title: 'Web Design', body: 'TTh (1:00PM-5:00PM)', instructor: 'Engr. Nicolas Sumagaysay', image: kulas, imagebg: webdes, id: 2 },
    //     { title: 'JavaScript Programming', body: 'MWF (7:00AM-10:00AM)', instructor: 'Engr. Phil Cajurao', image: phil, imagebg: js, id: 3 },
    //     { title: 'Calculus', body: 'TTh (1:00PM-5:00PM)', instructor: 'Engr. Jomari Dacles', image: daks, imagebg: mathbg, id: 4 },
    //     { title: 'Arduino', body: 'MWF (7:00AM-10:00AM)', instructor: 'Engr. Jomari Dacles', image: daks, imagebg: arduino, id: 5 },
    //     { title: 'Numerical Methods', body: 'TTh (1:00PM-5:00PM)', instructor: 'Engr. Jomari Dacles', image: daks, imagebg: mathbg, id: 6 },
    //     { title: 'Engineering Basics', body: 'MWF (7:00AM-10:00AM)', instructor: 'Engr. Phil Cajurao', image: phil, imagebg: engr, id: 7 },
    //     { title: 'Graphic Designing', body: 'TTh (1:00PM-5:00PM)', instructor: 'Engr. Nicolas Sumagaysay', image: kulas, imagebg: graphicdesign, id: 8 },
    //     { title: 'Python Programming', body: 'MWF (7:00AM-10:00AM)', instructor: 'Engr. Phil Cajurao', image: phil, imagebg: py, id: 9 },
    //     { title: 'Art App', body: 'TTh (1:00PM-5:00PM)', instructor: 'Engr. Nicolas Sumagaysay', image: kulas, imagebg: arts, id: 10 },
    // ])

    useEffect(() => {
        showClassrooms();
    }, []);

    const [subjects, setSubjects] = useState([]);

    function showClassrooms() {
        axios.get('http://localhost:80/api/getClassroom.php')
        .then((response) => {
            console.log(response.data)
            setSubjects(response.data);
            if(response.data.Status == 'Invalid') {
                alert('Invalid User');
            } else {
                // navigate('/teacherDashboard')
            }
        })
    }


    return (
        <>
            <Container>
                <Grid container spacing={7}>
                    {subjects.map(subject => (
                        <Grid item xs={12} sm={6} lg={3} zeroMinWidth key={subject.id}>
                            <SubjectCards subject={subject} />
                        </Grid>
                    ))}
                </Grid>
            </Container>
        </>
    )
}
